import{_ as s,c as a,o as t,ae as i}from"./chunks/framework.BHrE6nLq.js";const k=JSON.parse('{"title":"Setting Up a Local Yum Repository","description":"","frontmatter":{},"headers":[],"relativePath":"docs/how_to/repository/setup-local-repo.md","filePath":"docs/how_to/repository/setup-local-repo.md"}'),o={name:"docs/how_to/repository/setup-local-repo.md"};function l(n,e,r,h,p,d){return t(),a("div",null,e[0]||(e[0]=[i(`<h1 id="setting-up-a-local-yum-repository" tabindex="-1">Setting Up a Local Yum Repository <a class="header-anchor" href="#setting-up-a-local-yum-repository" aria-label="Permalink to &quot;Setting Up a Local Yum Repository&quot;">​</a></h1><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>A local Yum repository allows you to host and manage software packages on your own server, making it easier to install and update software without relying on an internet connection. In this guide, we’ll walk through the process of setting up a local repository on a RHEL-based system (e.g., Red Hat Enterprise Linux or Rocky Linux) using an operating system DVD ISO file and the Apache web server (<code>httpd</code>). By the end, you&#39;ll have a functional local repository accessible via a web browser.</p><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><p>Before starting, ensure you have the following:</p><ul><li>A DVD ISO file of the operating system (e.g., <code>rhel-8.6-x86_64-dvd.iso</code>).</li><li>A server or virtual machine running a RHEL-based OS.</li><li>The <code>tar</code> utility (usually pre-installed).</li><li>The <code>httpd</code> package (Apache web server).</li><li>The <code>createrepo</code> tool for generating repository metadata.</li></ul><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><h3 id="step-1-install-the-apache-web-server" tabindex="-1">Step 1 - Install the Apache Web Server <a class="header-anchor" href="#step-1-install-the-apache-web-server" aria-label="Permalink to &quot;Step 1 - Install the Apache Web Server&quot;">​</a></h3><p>If the Apache web server (<code>httpd</code>) isn’t already installed, install it using the <code>yum</code> package manager. Run the following command:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> httpd</span></span></code></pre></div><p>The <code>-y</code> flag automatically confirms the installation, saving you from manually approving it.</p><h3 id="step-2-enable-and-start-the-httpd-service" tabindex="-1">Step 2 - Enable and Start the HTTPD Service <a class="header-anchor" href="#step-2-enable-and-start-the-httpd-service" aria-label="Permalink to &quot;Step 2 - Enable and Start the HTTPD Service&quot;">​</a></h3><p>Once installed, enable the <code>httpd</code> service to start automatically on boot and launch it immediately. Use this command:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --now</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> httpd</span></span></code></pre></div><p>To verify that the service is running, check its status:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> httpd</span></span></code></pre></div><p>If successful, you’ll see output indicating that the service is <code>active (running)</code>. This confirms your web server is operational.</p><h3 id="step-3-create-a-directory-for-the-repository" tabindex="-1">Step 3 - Create a Directory for the Repository <a class="header-anchor" href="#step-3-create-a-directory-for-the-repository" aria-label="Permalink to &quot;Step 3 - Create a Directory for the Repository&quot;">​</a></h3><p>Next, create a directory to store your local repository files. This directory will be served by Apache, so we’ll place it under <code>/var/www/html</code>. For this example, we’ll name it <code>local_repo</code>, but you can choose any name:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/www/html/local_repo</span></span></code></pre></div><p>The <code>-p</code> flag ensures the parent directories are created if they don’t already exist.</p><h3 id="step-4-mount-the-iso-file" tabindex="-1">Step 4 - Mount the ISO File <a class="header-anchor" href="#step-4-mount-the-iso-file" aria-label="Permalink to &quot;Step 4 - Mount the ISO File&quot;">​</a></h3><p>Mount the DVD ISO file to a temporary directory (e.g., <code>/mnt</code>) to access its contents. Replace <code>rhel-8.6-x86_64-dvd.iso</code> with the name of your ISO file:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mount</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> loop</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rhel-8.6-x86_64-dvd.iso</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /mnt</span></span></code></pre></div><p>The <code>-o loop</code> option allows you to mount the ISO as a loop device without needing a physical DVD drive.</p><h3 id="step-5-extract-iso-contents" tabindex="-1">Step 5 - Extract ISO Contents <a class="header-anchor" href="#step-5-extract-iso-contents" aria-label="Permalink to &quot;Step 5 - Extract ISO Contents&quot;">​</a></h3><p>Navigate to the <code>/mnt</code> directory and extract the ISO’s contents into the repository directory (<code>/var/www/html/local_repo</code>). The <code>tar</code> command below copies everything efficiently:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /mnt</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tar</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cvf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> -</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/www/html/local_repo/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tar</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> xvf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>Here’s what this command does:</p><ul><li><code>tar cvf - .</code> archives the contents of <code>/mnt</code>.</li><li>The pipe <code>|</code> sends the archive to the target directory.</li><li><code>(cd /var/www/html/local_repo/; tar xvf -)</code> extracts it there.</li></ul><p>This process may take a few minutes, depending on the ISO size.</p><h3 id="step-6-install-the-createrepo-tool" tabindex="-1">Step 6 - Install the <code>createrepo</code> Tool <a class="header-anchor" href="#step-6-install-the-createrepo-tool" aria-label="Permalink to &quot;Step 6 - Install the \`createrepo\` Tool&quot;">​</a></h3><p>To turn the extracted files into a usable Yum repository, you’ll need the <code>createrepo</code> package. Install it along with <code>yum-utils</code> for additional repository management tools:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> createrepo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> yum-utils</span></span></code></pre></div><h3 id="step-7-generate-the-repository-metadata" tabindex="-1">Step 7 - Generate the Repository Metadata <a class="header-anchor" href="#step-7-generate-the-repository-metadata" aria-label="Permalink to &quot;Step 7 - Generate the Repository Metadata&quot;">​</a></h3><p>Run the <code>createrepo</code> command to create the necessary metadata files for your local repository:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> createrepo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/www/html/local_repo/</span></span></code></pre></div><p>This generates a <code>repodata</code> directory inside <code>/var/www/html/local_repo/</code>, which Yum uses to recognize the repository.</p><h3 id="step-8-test-the-repository" tabindex="-1">Step 8 - Test the Repository <a class="header-anchor" href="#step-8-test-the-repository" aria-label="Permalink to &quot;Step 8 - Test the Repository&quot;">​</a></h3><p>Your local repository is now ready! Open a web browser and enter the following URL, replacing <code>&lt;ip-address&gt;</code> with your server’s IP address:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://&lt;ip-address&gt;/local_repo</span></span></code></pre></div><p>For example, if your server’s IP is <code>192.168.1.100</code>, you’d visit <code>http://192.168.1.100/local_repo</code>. You should see a directory listing of the repository files.</p><blockquote><p><strong>Note</strong>: Adjust the URL based on your server’s IP address and the repository directory name if you used something other than <code>local_repo</code>.</p></blockquote><h3 id="optional-configure-yum-to-use-the-local-repository" tabindex="-1">Optional - Configure Yum to Use the Local Repository <a class="header-anchor" href="#optional-configure-yum-to-use-the-local-repository" aria-label="Permalink to &quot;Optional - Configure Yum to Use the Local Repository&quot;">​</a></h3><p>To use this repository with Yum, create a <code>.repo</code> file in <code>/etc/yum.repos.d/</code>. For example:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tee</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/yum.repos.d/local_repo.repo</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">EOF</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">[local_repo]</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">name=Local Repository</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">baseurl=http://&lt;ip-address&gt;/local_repo</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">enabled=1</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">gpgcheck=0</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">EOF</span></span></code></pre></div><p>Replace <code>&lt;ip-address&gt;</code> with your server’s IP. Then, test it with:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> repolist</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li><a href="https://www.redhat.com/sysadmin/apache-yum-dnf-repo" target="_blank" rel="noreferrer">Red Hat Sysadmin Guide: Apache Yum/DNF Repo</a></li><li><a href="https://www.linuxtechi.com/create-local-yum-dnf-repository-rhel/#google_vignette" target="_blank" rel="noreferrer">LinuxTechi: Create Local Yum/DNF Repository on RHEL</a></li></ul>`,50)]))}const u=s(o,[["render",l]]);export{k as __pageData,u as default};
